sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.recent-requests{

    padding:60px;
    background:#ffffff;

}

.recent-requests h2{

    text-align:center;
    color:#0F4C81;
    margin-bottom:35px;

}

.recent-table{

    width:100%;
    border-collapse:collapse;
    background:white;
    box-shadow:0 8px 18px rgba(0,0,0,.08);

}

.recent-table th{

    background:#0F4C81;
    color:white;
    padding:15px;

}

.recent-table td{

    padding:15px;
    border-bottom:1px solid #eeeeee;

}

.recent-table tr:hover{

    background:#f8f9fc;

}

.view-all{

    text-align:right;
    margin-top:25px;

}

.view-all a{

    color:#0F4C81;
    text-decoration:none;
    font-weight:bold;

}

.view-all a:hover{

    text-decoration:underline;

}

sp_widget.script:
(function() {

    data.requests = [];

    var gr = new GlideRecord('x_1958816_enterp_0_network_request');
    gr.orderByDesc('sys_created_on');
    gr.setLimit(5);
    gr.query();

    while (gr.next()) {

        data.requests.push({
            number: gr.getValue('number'),
            request_type: gr.getDisplayValue('request_type'),
            priority: gr.getDisplayValue('priority'),
            state: gr.getDisplayValue('state')
        });

    }

})();
